// Compute week range: previous Monday 00:00 UTC to Sunday 23:59:59 UTC
const now = new Date();
const day = now.getUTCDay(); // 0=Sun, 1=Mon, ...

// Find this Monday
const thisMonday = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()));
const diff = day === 0 ? 6 : day - 1;
thisMonday.setUTCDate(thisMonday.getUTCDate() - diff);

// Previous Monday is 7 days before this Monday
const prevMonday = new Date(thisMonday);
prevMonday.setUTCDate(prevMonday.getUTCDate() - 7);

// Sunday is 6 days after previous Monday
const prevSunday = new Date(prevMonday);
prevSunday.setUTCDate(prevSunday.getUTCDate() + 6);

const weekStart = prevMonday.toISOString().slice(0, 10);
const weekEnd = prevSunday.toISOString().slice(0, 10);

return [{ json: { week_start: weekStart, week_end: weekEnd } }];

// Score and select top signals per section
// Max 6 per section, max 25 total
const signals = $input.all().map(item => item.json);
const weekRange = $('Compute Week Range').first().json;

const sections = ['messaging', 'narrative', 'icp', 'horizon'];
const maxPerSection = 6;
const maxTotal = 25;

const selectedBySection = {};
let totalSelected = [];

for (const section of sections) {
  const sectionSignals = signals
    .filter(s => s.signal_type === section)
    .slice(0, maxPerSection);
  selectedBySection[section] = sectionSignals;
  totalSelected = totalSelected.concat(sectionSignals);
}

// If we exceed maxTotal, trim from lowest-scoring signals
if (totalSelected.length > maxTotal) {
  totalSelected.sort((a, b) => b.score - a.score);
  totalSelected = totalSelected.slice(0, maxTotal);
}

// Build signal summaries for LLM prompt
const signalSummaries = {};
for (const section of sections) {
  signalSummaries[section] = selectedBySection[section].map(s => ({
    id: s.id,
    severity: s.severity,
    title: s.title,
    summary: s.summary
  }));
}

// Build the Anthropic API request body
const systemPrompt = 'You are a GTM intelligence analyst creating weekly packets for a PMM team. Synthesize signals into actionable intelligence. Output STRICT JSON only with these fields: packet_title (string), exec_summary (array max 7 bullets), sections (object with messaging, narrative, icp, horizon - each having summary and highlights), key_questions (array 3-5), bets (array up to 3 with hypothesis, signal_ids, confidence).';

const userContent = 'Week: ' + weekRange.week_start + ' to ' + weekRange.week_end + '. Total signals: ' + signals.length + '. Selected: ' + totalSelected.length + '. MESSAGING: ' + JSON.stringify(signalSummaries.messaging) + '. NARRATIVE: ' + JSON.stringify(signalSummaries.narrative) + '. ICP: ' + JSON.stringify(signalSummaries.icp) + '. HORIZON: ' + JSON.stringify(signalSummaries.horizon) + '. Synthesize into weekly GTM intelligence packet.';

const anthropicBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 2000,
  temperature: 0.3,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
};

return [{ json: {
  week_start: weekRange.week_start,
  week_end: weekRange.week_end,
  total_signals: signals.length,
  selected_count: totalSelected.length,
  selected_signals: totalSelected,
  signal_summaries: signalSummaries,
  anthropic_body: anthropicBody
}}];

// Parse Anthropic response and extract packet JSON
const resp = $input.first().json;
const selectData = $('Score + Select Top Signals').first().json;

let packetData;
try {
  const content = resp.content?.[0]?.text || '{}';
  packetData = JSON.parse(content);
} catch (e) {
  // Fallback if parsing fails
  packetData = {
    packet_title: `Week of ${selectData.week_start}: Intelligence Packet`,
    exec_summary: ['Signal synthesis failed - manual review required'],
    sections: {
      messaging: { summary: 'Parsing error', highlights: [] },
      narrative: { summary: 'Parsing error', highlights: [] },
      icp: { summary: 'Parsing error', highlights: [] },
      horizon: { summary: 'Parsing error', highlights: [] }
    },
    key_questions: ['Review raw signals for this week'],
    bets: []
  };
}

return [{ json: {
  ...selectData,
  packet: packetData
}}];

// Prepare packet_items for insertion
const packetId = $('Upsert Packet').first().json.id;
const selectData = $('Parse Packet JSON').first().json;

const items = selectData.selected_signals.map((signal, idx) => ({
  packet_id: packetId,
  signal_id: signal.id,
  section: signal.signal_type,
  rank: idx + 1,
  score: signal.score
}));

return items.map(item => ({ json: item }));

