=INSERT INTO control_plane.packet_items (packet_id, signal_id, section, rank, score)
VALUES (
  '{{ $json.packet_id }}',
  '{{ $json.signal_id }}',
  '{{ $json.section }}',
  {{ $json.rank }},
  {{ $json.score }}
)
ON CONFLICT (packet_id, signal_id) DO UPDATE
SET section = EXCLUDED.section, rank = EXCLUDED.rank, score = EXCLUDED.score;
